class Solution {
    public int minChanges(int[] nums, int k) {
        int n = nums.length;
        int[] freq = new int[1024];
        int[][] group = new int[k][1024];
        int[] size = new int[k];
        for (int i = 0; i < n; ++i) {
            int idx = i % k;
            group[idx][nums[i]]++;
            size[idx]++;
        }
        int[] dp = new int[1024];
        for (int i = 0; i < 1024; ++i) dp[i] = n;
        dp[0] = 0;
        for (int i = 0; i < k; ++i) {
            int minPrev = n;
            for (int x = 0; x < 1024; ++x) minPrev = Math.min(minPrev, dp[x]);
            int[] next = new int[1024];
            for (int x = 0; x < 1024; ++x) next[x] = minPrev + size[i];
            for (int x = 0; x < 1024; ++x) {
                if (dp[x] == n) continue;
                for (int v = 0; v < 1024; ++v) {
                    int y = x ^ v;
                    next[y] = Math.min(next[y], dp[x] + size[i] - group[i][v]);
                }
            }
            dp = next;
        }
        return dp[0];
    }
}
